// Transform raw webhook into structured report data
const data = $input.first().json;

const shopify = data.shopify || {};
const google = data.googleAds || {};
const sources = data.dataSources || {};

// Shopify metrics
const orders = shopify.orderCount || 0;
const grossSales = shopify.grossSales || 0;
const refunds = shopify.refundedOrders || 0;
const cancelled = shopify.cancelledOrders || 0;
const refundRate = orders > 0 ? ((refunds / orders) * 100).toFixed(1) : '0';

// Source breakdown
const sourceBreakdown = shopify.sourceBreakdown || {};
const sourceRows = Object.entries(sourceBreakdown)
  .map(([name, d]) => ({ name, orders: d.orders, revenue: d.revenue }))
  .sort((a, b) => b.revenue - a.revenue);

// Google Ads metrics
const adSpend = google.totalSpend || 0;
const adRevenue = google.totalRevenue || 0;
const adConversions = google.totalConversions || 0;
const adRoas = google.roas || 0;
const campaigns = (google.campaigns || []).slice(0, 6);

// Combined
const totalRevenue = grossSales;
const blendedRoas = adSpend > 0 ? (totalRevenue / adSpend).toFixed(1) : 'N/A';

// Flags
const flags = [];
if (parseFloat(refundRate) > 5) flags.push(`Refund rate at ${refundRate}% — route to Sammie`);
if (adSpend > 10000) flags.push(`Ad spend above $10K ceiling — route to Christopher`);
if (adRoas > 0 && adRoas < 5) flags.push(`ROAS below 5:1 — route to Kevin + Zo`);

// No-referrer tracking (attribution anomaly)
const noRefOrders = sourceBreakdown['web']?.orders || sourceBreakdown['unknown']?.orders || 0;
const noRefRevenue = sourceBreakdown['web']?.revenue || sourceBreakdown['unknown']?.revenue || 0;
const noRefPct = orders > 0 ? ((noRefOrders / orders) * 100).toFixed(0) : '0';

return [{
  json: {
    runDate: data.runDate,
    briefing: data.briefing,
    smsSent: data.smsSent,
    timestamp: data.timestamp,
    orders,
    grossSales: grossSales.toFixed(2),
    refunds,
    refundRate,
    cancelled,
    adSpend: adSpend.toFixed(2),
    adRevenue: adRevenue.toFixed(2),
    adConversions,
    adRoas: adRoas.toFixed(1),
    blendedRoas,
    campaigns,
    sourceRows,
    flags,
    noRefPct,
    noRefRevenue: noRefRevenue.toFixed(2),
    googleOk: sources.google?.ok || false,
    metaOk: sources.meta?.ok || false,
    shopifyOk: sources.shopify?.ok || false,
  }
}];
